const defaults = {
  loadKw: 60,
  pvAvailableKw: 20,
  loadRangeKw: 10,
  pvRangeKw: 10,
  soc: 0.62,
  gridOutage: false,
  bmsNormal: true,
  pcsFault: false,
  maxCellVoltageV: 3.38,
  minCellVoltageV: 3.12,
  batteryVoltageV: 1100,
  crdMode: 'no-export',
  siteExportMode: 'no-restriction',
  siteExportTargetImportKw: 0.5,
  siteExportDeadbandKw: 0.8,
  scheduledControlEnabled: false
};
let input = Object.assign({}, defaults, flow.get('simInput') || {});
if (msg.topic === 'scenario' && msg.payload === 'reset-history') {
  flow.set('simHistory', []);
  node.status({ fill: 'blue', shape: 'ring', text: 'history cleared in context' });
  return null;
}
if (msg.topic === 'scenario' && msg.payload === 'reset') {
  flow.set('simState', null);
  flow.set('controlState', null);
  flow.set('islandingState', { mode: 'idle' });
  flow.set('generatorState', { mode: 'idle' });
  input = Object.assign({}, defaults);
} else if (msg.topic) {
  input[msg.topic] = msg.payload;
}
for (const key of ['loadKw','pvAvailableKw','loadRangeKw','pvRangeKw','soc','maxCellVoltageV','minCellVoltageV','batteryVoltageV','siteExportTargetImportKw','siteExportDeadbandKw']) input[key] = Number(input[key]);
for (const key of ['gridOutage','bmsNormal','pcsFault','scheduledControlEnabled']) input[key] = input[key] === true || input[key] === 'true';
if (!['no-export','no-import','no-exchange','no-restriction'].includes(input.crdMode)) input.crdMode = 'no-export';
if (!['no-export','no-restriction'].includes(input.siteExportMode)) input.siteExportMode = 'no-restriction';
flow.set('simInput', input);
msg.payload = input;
return msg;

const lib = global.get('lib');
if (!lib || !lib.scheduler || !lib.coreControl) {
  node.error('global lib with scheduler/coreControl is unavailable', msg);
  return null;
}

const input = Object.assign({ loadKw: 60, pvAvailableKw: 20, loadRangeKw: 10, pvRangeKw: 10, soc: 0.62, gridOutage: false, bmsNormal: true, pcsFault: false, maxCellVoltageV: 3.38, minCellVoltageV: 3.12, batteryVoltageV: 1100, crdMode: 'no-export', siteExportMode: 'no-restriction', siteExportTargetImportKw: 0.5, siteExportDeadbandKw: 0.8, scheduledControlEnabled: false }, flow.get('simInput') || {});
let s = flow.get('simState') || {
  pcsDemandKw: 0,
  pcsMeasuredKw: 0,
  pcsOnOff: 1,
  pcsRunMode: 0,
  gridWireConnection: 0,
  pcsGlobalState: 3,
  pvLimitPct: 1,
  pvLimitTargetPct: 1,
  selInterlock: false,
  genRelay: false,
  generatorRunning: false,
  generatorDelay: 0,
  soc: input.soc,
  loadActualKw: input.loadKw,
  pvAvailableActualKw: input.pvAvailableKw
};

function clamp(x, lo, hi) { return Math.max(lo, Math.min(hi, x)); }
function ramp(cur, tgt, step) { return cur + clamp(tgt - cur, -step, step); }
function wander(cur, base, span, step, lo) {
  const safeSpan = Math.max(0, Number(span) || 0);
  if (safeSpan <= 0) return Math.max(lo, base);
  const current = Number.isFinite(cur) ? cur : base;
  const boundedStep = clamp(Math.max(0, Number(step) || 0), 0, safeSpan);
  const drift = (base - current) * 0.08;
  const noise = (Math.random() * 2 - 1) * boundedStep;
  return clamp(current + drift + noise, Math.max(lo, base - safeSpan), base + safeSpan);
}
function pcsOnOffLabel(v) { return v === 1 ? 'ON' : v === 2 ? 'OFF' : `UNKNOWN ${v}`; }
function runModeLabel(v) { return v === 0 ? 'GRID_TIE' : v === 1 ? 'STANDALONE' : `MODE_${v}`; }
function gwcLabel(v) { return v === 0 ? 'GRID_TIE' : v === 1 ? 'ISLAND' : `GWC_${v}`; }
function pcsGlobalStateLabel(v) {
  switch (v) {
    case 1: return 'STANDBY';
    case 3: return 'GRID_TIE_NORMAL';
    case 6: return 'STANDALONE_NORMAL';
    case 7: return 'FAULT';
    default: return `STATE_${v}`;
  }
}
function bmsStatusLabel(v) { return v === 1 ? 'NORMAL' : v === 2 ? 'ABNORMAL' : `BMS_${v}`; }
function applyEnvelope(env) {
  if (!env || !Array.isArray(env.payload)) return;
  for (const c of env.payload) {
    switch (c.tagID) {
      case 'SYSTEM_ACTIVE_POWER_DEMAND': s.pcsDemandKw = Number(c.value) || 0; break;
      case 'PCS.SYSTEM_ACTIVE_POWER_DEMAND': s.pcsDemandKw = Number(c.value) || 0; break;
      case 'SYSTEM_ON_OFF': s.pcsOnOff = Number(c.value); break;
      case 'PCS.SYSTEM_ON_OFF': s.pcsOnOff = Number(c.value); break;
      case 'SYSTEM_RUN_MODE': s.pcsRunMode = Number(c.value); break;
      case 'PCS.SYSTEM_RUN_MODE': s.pcsRunMode = Number(c.value); break;
      case 'GRID_WIRE_CONNECTION': s.gridWireConnection = Number(c.value); break;
      case 'PCS.GRID_WIRE_CONNECTION': s.gridWireConnection = Number(c.value); break;
      case 'SEL751.RB_1':
      case 'SEL851.RB_1': s.selInterlock = !!c.value; break;
      case 'SEL851.RB_2':
      case 'RemoteIO.Generator_Start': s.genRelay = !!c.value; break;
      case 'SolarEdge1.Dynamic_Active_Power_Limit':
      case 'SolarEdge2.Dynamic_Active_Power_Limit': s.pvLimitTargetPct = clamp(Number(c.value), 0, 1); break;
    }
  }
}
for (const env of flow.get('lastWriterEnvelopes') || []) applyEnvelope(env);

if (s.genRelay && !s.generatorRunning) s.generatorDelay += 1;
else if (!s.genRelay) { s.generatorDelay = 0; s.generatorRunning = false; }
if (s.generatorDelay >= 3) s.generatorRunning = true;

if (input.pcsFault) s.pcsGlobalState = 7;
else if (s.pcsOnOff === 2) s.pcsGlobalState = 1;
else if (s.pcsRunMode === 1) s.pcsGlobalState = 6;
else s.pcsGlobalState = 3;

const pcsAllowed = s.pcsOnOff === 1 && !input.pcsFault && input.bmsNormal;
const loadBaseKw = Math.max(0, Number(input.loadKw) || 0);
const pvBaseKw = Math.max(0, Number(input.pvAvailableKw) || 0);
const loadRangeKw = Math.max(0, Number(input.loadRangeKw) || 0);
const pvRangeKw = Math.max(0, Number(input.pvRangeKw) || 0);
s.loadActualKw = wander(s.loadActualKw, loadBaseKw, loadRangeKw, loadRangeKw * 0.12, 0);
s.pvAvailableActualKw = wander(s.pvAvailableActualKw, pvBaseKw, pvRangeKw, pvRangeKw * 0.12, 0);
const loadActualKw = Number(s.loadActualKw.toFixed(3));
const pvAvailableActualKw = Number(s.pvAvailableActualKw.toFixed(3));
s.pvLimitTargetPct = Number.isFinite(s.pvLimitTargetPct) ? clamp(s.pvLimitTargetPct, 0, 1) : 1;
s.pvLimitPct = ramp(Number.isFinite(s.pvLimitPct) ? s.pvLimitPct : 1, s.pvLimitTargetPct, 0.05);
const pvActualKw = clamp(pvAvailableActualKw * s.pvLimitPct, 0, pvAvailableActualKw);
const standaloneMode = input.gridOutage || s.pcsRunMode === 1 || s.gridWireConnection === 1;
const islandBalanceKw = loadActualKw - pvActualKw;
const pcsTargetKw = standaloneMode ? islandBalanceKw : s.pcsDemandKw;
s.pcsMeasuredKw = pcsAllowed ? ramp(s.pcsMeasuredKw, pcsTargetKw, 20) : ramp(s.pcsMeasuredKw, 0, 30);
const utilityKw = standaloneMode ? 0 : loadActualKw - pvActualKw - s.pcsMeasuredKw;
if (msg.topic === 'soc' || !Number.isFinite(s.soc)) s.soc = clamp(Number.isFinite(input.soc) ? input.soc : s.soc, 0, 1);
s.soc = clamp(s.soc - (s.pcsMeasuredKw / 280 / 3600), 0, 1);

const batteryVoltageV = clamp(Number(input.batteryVoltageV) || 1100, 1000, 1200);
const maxChargeCurrentAllowedA = input.maxCellVoltageV >= 3.57 ? 0 : -120;
const maxDischargeCurrentAllowedA = input.minCellVoltageV <= 2.9 ? 0 : 120;
const bmsStatus = input.bmsNormal ? 1 : 2;

const telemetry = {
  Meter: [
    { tagID: 'Meter.Utility_Total_Power', value: utilityKw },
    { tagID: 'Meter.Load_Total_Power', value: loadActualKw },
    { tagID: 'Meter.PV_Total_Power', value: pvActualKw },
    { tagID: 'Meter.BESS_Total_Power', value: s.pcsMeasuredKw },
    { tagID: 'Meter.POI_kW', value: utilityKw }
  ],
  PCS: [
    { tagID: 'PCS.SYSTEM_ACTIVE_POWER_DEMAND', value: s.pcsDemandKw },
    { tagID: 'PCS.SYSTEM_POWER_ACTIVE_ALL', value: s.pcsMeasuredKw },
    { tagID: 'PCS.SYSTEM_ON_OFF', value: s.pcsOnOff },
    { tagID: 'PCS.SYSTEM_RUN_MODE', value: s.pcsRunMode },
    { tagID: 'PCS.GRID_WIRE_CONNECTION', value: s.gridWireConnection },
    { tagID: 'PCS.SYSTEM_GLOBAL_STATE', value: s.pcsGlobalState },
    { tagID: 'PCS.SYS_TIME_MIN_SEC', value: Math.floor(Date.now() / 1000) % 3600 }
  ],
  MBMU: [
    { tagID: 'MBMU.System_SOC_pct', value: s.soc },
    { tagID: 'MBMU.system_SOC_raw', value: s.soc },
    { tagID: 'MBMU.System_Voltage_V', value: batteryVoltageV },
    { tagID: 'MBMU.Max_Charge_Current_Allowed_A', value: maxChargeCurrentAllowedA },
    { tagID: 'MBMU.Max_Discharge_Current_Allowed_A', value: maxDischargeCurrentAllowedA },
    { tagID: 'MBMU.Max_Cell_Voltage_V', value: input.maxCellVoltageV },
    { tagID: 'MBMU.Min_Cell_Voltage_V', value: input.minCellVoltageV },
    { tagID: 'MBMU.BMS_Status', value: bmsStatus }
  ],
  SEL751: [
    { tagID: 'SEL751.ROW_48', value: input.gridOutage ? 128 : 0 },
    { tagID: 'SEL751.SV01T', value: input.gridOutage ? 1 : 0 },
    { tagID: 'SEL751.RB_1', value: s.selInterlock },
    { tagID: 'SEL751.RB_2', value: s.genRelay }
  ],
  SEL851: [
    { tagID: 'SEL851.ROW_46', value: input.gridOutage ? 128 : 0 },
    { tagID: 'SEL851.ROW_33', value: s.generatorRunning ? 4 : 8 },
    { tagID: 'SEL851.RB_1', value: s.selInterlock },
    { tagID: 'SEL851.RB_2', value: s.genRelay }
  ]
};
global.set('telemetry', telemetry);

const siteConfig = {
  system: { systemProfile: 'eSpire280', controllerTimezone: 'America/Los_Angeles', nominal: { voltageVll: 480, frequencyHz: 60 } },
  network: { controller: { ip: '192.168.1.10', modbusServer: { ip: '192.168.1.20', port: 502 } } },
  operation: { mode: input.gridOutage ? 'off-grid' : 'grid-tied', gridCode: 'IEEE1547-2018', crdMode: input.crdMode || 'no-export', siteExportMode: input.siteExportMode || 'no-restriction', siteExportTargetImportKw: Number(input.siteExportTargetImportKw) || 0, siteExportDeadbandKw: Number(input.siteExportDeadbandKw) || 0, scheduledControlEnabled: input.scheduledControlEnabled === true },
  pcs: { pcsDaisyChain: [1, 1], maxChargeKw: 250, maxDischargeKw: 250 },
  mbmu: { sbmuStrings: [2, 2] },
  battery: { minSoc: 0.1, maxSoc: 0.95, socLow: 0.3, socLowRecover: 0.22, socHigh: 0.95, socHighRecover: 0.92, forceGridChargeSoc: 0.15, forceGridChargeMinCellVoltageV: 2.95, forceGridChargeKw: 10, powerHeadroomKw: 2, commandRampKwPerSec: 25 },
  pv: { acInverters: [{ id: 'SolarEdge1', type: 'SolarEdge', model: 'SE60K', ratedKwAc: 60, ip: '192.168.1.201', port: 502, modbusProfile: 'solaredge_v1' }, { id: 'SolarEdge2', type: 'SolarEdge', model: 'SE60K', ratedKwAc: 60, ip: '192.168.1.202', port: 502, modbusProfile: 'solaredge_v1' }], curtailmentMethod: 'modbus' },
  islanding: { device: 'SEL751' },
  metering: {
    meterType: 'sim', modbusProfile: 'sim', ip: '127.0.0.1',
    reads: { pv: true, pvFromInverter: false, utility: true, load: true },
    calculations: {
      utilityPowerKw: { source: 'tag', tagID: 'Meter.POI_kW' },
      siteLoadKw: { source: 'tag', tagID: 'Meter.Load_Total_Power' },
      pvKw: { source: 'tag', tagID: 'Meter.PV_Total_Power' }
    }
  },
  generator: { maxKw: 50, chargeFromGenerator: true, chargeKwLimit: 30, startSoc: 0.2, stopSoc: 0.9, controlType: 'SEL' }
};
const plans = [{ planID: 'sim-default', default: true, strategy: { meter_rule: { discharge: { net_load_threshold: { value: 20, unit: 'kW' } }, charge: { net_load_threshold: { value: 1, unit: 'kW' } } } } }];
const activePlan = lib.scheduler.matchActiveSchedulePlan(plans, { now: new Date(), timezone: siteConfig.system.controllerTimezone });
const schedule = activePlan ? lib.scheduler.scheduleOutputFromActivePlan(activePlan) : {};
const scheduleDetails = {
  selectedPlan: schedule.selectedPlan || null,
  planID: schedule.selectedPlan?.planID || activePlan?.plan?.planID || null,
  name: schedule.selectedPlan?.name || activePlan?.plan?.name || null,
  reason: schedule.selectedPlan?.reason || activePlan?.selectedReason || null,
  via: schedule.selectedPlan?.via || activePlan?.via || null,
  isFallback: schedule.selectedPlan?.isFallback || activePlan?.isFallback || false,
  nextTimedStart: schedule.selectedPlan?.nextTimedStart || activePlan?.nextTimedStart || null,
  activePowerKwSetpoint: schedule.activePowerKwSetpoint ?? null,
