  telemetry: { 'Meter.POI_kW': utilityKw, 'Meter.Load_Total_Power': loadActualKw, 'Meter.PV_Total_Power': pvActualKw },
  baseTelemetry: {
    soc: s.soc,
    gridStatus: input.gridOutage ? 'island' : 'normal',
    pcsActivePowerKw: s.pcsMeasuredKw,
    generatorRunning: s.generatorRunning,
    protectionState: input.gridOutage ? 'islanded' : 'normal',
    pcsRunAllowed: true,
    remoteInterlockClosed: true,
    machineStatus: { batteryVoltageV, maxChargeCurrentAllowedA, maxDischargeCurrentAllowedA, maxCellVoltageV: input.maxCellVoltageV, minCellVoltageV: input.minCellVoltageV, bmsStatus, pcsGlobalState: s.pcsGlobalState }
  },
  schedule,
  state: controlState,
  nowMs: controlNowMs
});
flow.set('controlState', controlState);
let generatorState = flow.get('generatorState') || { mode: 'idle' };
const generator = lib.coreControl.evaluateGeneratorSequencer(siteConfig.generator, { batterySoc: s.soc, generatorRunning: s.generatorRunning, generatorAvailable: true, allowGeneratorStart: input.gridOutage === true }, generatorState);
flow.set('generatorState', generator.state);
const genEnvelopes = lib.coreControl.generatorCommandsToWriterEnvelopes(siteConfig.generator, generator.commands);
let islandingState = flow.get('islandingState') || { mode: 'idle' };
const islanding = lib.coreControl.evaluateESpire280IslandingSequencer({ outageDetected: input.gridOutage, interlockClosed: s.selInterlock, pcsOnOff: s.pcsOnOff, pcsGlobalState: s.pcsGlobalState, pcsRunMode: s.pcsRunMode, gridWireConnection: s.gridWireConnection }, islandingState);
flow.set('islandingState', islanding.state);
const islandEnvelopes = lib.coreControl.islandingCommandsToWriterEnvelopes(islanding.commands);
const pvCurtailmentAllowed = standaloneMode || input.siteExportMode === 'no-export';
const pvLimitTarget = cycle.command.pvActivePowerLimitPct != null
  ? clamp(Number(cycle.command.pvActivePowerLimitPct), 0, 1)
  : 1;
const pvEnvelopes = cycle.writerEnvelopes.filter(env => String(env.topic || '').startsWith('SolarEdge'));
const allEnvelopes = [...cycle.writerEnvelopes, ...genEnvelopes, ...islandEnvelopes];
flow.set('lastWriterEnvelopes', allEnvelopes);
flow.set('simState', s);

msg.payload = {
  input,
  plant: {
    utilityKw,
    loadKw: loadActualKw,
    loadBaseKw,
    loadRangeKw,
    pvAvailableKw: pvAvailableActualKw,
    pvBaseKw,
    pvRangeKw,
    pvActualKw,
    pvLimitPct: s.pvLimitPct,
    pvLimitTargetPct: s.pvLimitTargetPct,
    standaloneMode,
    islandBalanceKw,
    pcsMeasuredKw: s.pcsMeasuredKw,
    pcsDemandKw: s.pcsDemandKw,
    soc: s.soc,
    pcsOnOff: s.pcsOnOff,
    pcsOnOffLabel: pcsOnOffLabel(s.pcsOnOff),
    pcsRunMode: s.pcsRunMode,
    pcsRunModeLabel: runModeLabel(s.pcsRunMode),
    gridWireConnection: s.gridWireConnection,
    gridWireConnectionLabel: gwcLabel(s.gridWireConnection),
    pcsGlobalState: s.pcsGlobalState,
    pcsGlobalStateLabel: pcsGlobalStateLabel(s.pcsGlobalState),
    selInterlock: s.selInterlock,
    generatorRunning: s.generatorRunning,
    genRelay: s.genRelay
  },
  mbmu: {
    bmsStatus,
    bmsStatusLabel: bmsStatusLabel(bmsStatus),
    batteryVoltageV,
    maxChargeCurrentAllowedA,
    maxDischargeCurrentAllowedA,
    maxCellVoltageV: input.maxCellVoltageV,
    minCellVoltageV: input.minCellVoltageV,
    soc: s.soc
  },
  pcs: {
    onOff: s.pcsOnOff,
    onOffLabel: pcsOnOffLabel(s.pcsOnOff),
    runMode: s.pcsRunMode,
    runModeLabel: runModeLabel(s.pcsRunMode),
    gridWireConnection: s.gridWireConnection,
    gridWireConnectionLabel: gwcLabel(s.gridWireConnection),
    globalState: s.pcsGlobalState,
    globalStateLabel: pcsGlobalStateLabel(s.pcsGlobalState),
    demandKw: s.pcsDemandKw,
    measuredKw: s.pcsMeasuredKw
