  schedule: scheduleDetails,
  control: { command: cycle.command, pipeline: cycle.pipeline, writerEnvelopes: cycle.writerEnvelopes },
  generator: { state: generator.state, commands: generator.commands, reasons: generator.reasons, writerEnvelopes: genEnvelopes },
  islanding: { step: islanding.state.mode, state: islanding.state, commands: islanding.commands, reasons: islanding.reasons, writerEnvelopes: islandEnvelopes },
