  diagnostics: { historyCount: (flow.get('simHistory') || []).length, historyFile: '/data/node-red/control-sim-history.jsonl' },
  allWriterEnvelopes: allEnvelopes
};
return msg;

const p = msg.payload || {};
const plant = p.plant || {};
const now = Date.now();
return [
  { topic: 'Load kW', payload: plant.loadKw, timestamp: now },
  { topic: 'PV kW', payload: plant.pvActualKw, timestamp: now },
  { topic: 'Utility kW', payload: plant.utilityKw, timestamp: now },
  { topic: 'BESS kW', payload: plant.pcsMeasuredKw, timestamp: now }
];

const p = msg.payload || {};
const sample = {
  ts: new Date().toISOString(),
  input: p.input,
  plant: p.plant,
  mbmu: p.mbmu,
  pcs: p.pcs,
  schedule: p.schedule,
  control: {
    command: p.control && p.control.command,
    pipelineBlocked: p.control && p.control.pipeline && p.control.pipeline.blocked,
    activeStageIds: p.control && p.control.pipeline && p.control.pipeline.activeStageIds,
    warnings: p.control && p.control.pipeline && p.control.pipeline.warnings
  },
  generator: {
    state: p.generator && p.generator.state,
    commands: p.generator && p.generator.commands,
    reasons: p.generator && p.generator.reasons
  },
  islanding: {
    step: p.islanding && p.islanding.step,
    state: p.islanding && p.islanding.state,
    commands: p.islanding && p.islanding.commands,
    reasons: p.islanding && p.islanding.reasons
  },
  pvCurtailment: p.pvCurtailment,
  writerEnvelopes: p.allWriterEnvelopes
};
let history = flow.get('simHistory') || [];
history.push(sample);
if (history.length > 900) history = history.slice(-900);
flow.set('simHistory', history);
node.status({ fill: 'green', shape: 'dot', text: `${history.length} samples` });
msg.payload = JSON.stringify(sample);
return msg;
